SELECT COUNT(*) 
FROM c7d2503t1p1.receipts 
WHERE originalfilename = #{filename}

SELECT r.upload_id, r.member_idx, r.ocr_store, r.ocr_amount, r.ocr_date, r.upload_time, r.upload_status, m.member_id, m.member_name FROM receipts r JOIN member m ON r.member_idx = m.member_idx
ORDER BY r.ocr_amount DESC ORDER BY r.ocr_amount ASC ORDER BY r.upload_id DESC
LIMIT #{pageStart}, #{perPageNum}
